var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 현실 전초기지, <color=#ffd34c>쉘터 No.72</color>\\n관리국 제4 수색전대 <color=#ffd34c>야크샤</color> 임시 본부","JPN":"管理局現実前哨基地、<color=#ffd34c>シェルターNo.72</color>\\n管理局第4捜索戦隊<color=#ffd34c>ヤクシャー</color>臨時本部","ENG":"Administration's Normalside Frontier Base, <color=#ffd34c>Shelter No. 72</color>\\nAdministration 4th Recon Division <color=#ffd34c>Yaksha</color>'s temporary HQ","TWN":"管理局現世前哨站，<color=#ffd34c>72號庇護所</color>\\n管理局第4偵察戰隊<color=#ffd34c>夜叉</color>臨時總部"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"아야야……! 너무 세게 묶는 거 아니야? 살살 좀 하라고!","JPN":"いたた……！　強く縛りすぎだぞ！　手加減しろよ！","ENG":"Oww...! Don't you think you're tying me up too tight? Be gentle!","TWN":"嗷……！你是不是綁得太緊了？輕一點！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 보기보다 엄살이 심하구나?","JPN":"ふふ、大げさね。","ENG":"Fu fuu, didn't take you for a crybaby.","TWN":"呵呵，你很會裝嘛？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"다행히 상처가 침식파에 오염되지는 않았어. 몸이 튼튼해서 다행이네.","JPN":"幸い、傷口も侵食波に汚染されてない。丈夫な体でよかったね。","ENG":"Luckily, your wound isn't contaminated by the Corruption ray. Thank goodness your body's strong.","TWN":"幸好傷口沒有被侵蝕波感染。多虧了你這副強壯的身體。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"4종 정도 되는 침식체에게 입은 부상은 아무리 가벼운 상처라도 얕볼 수 없거든.","JPN":"第4種くらいの侵食体にやられた傷はどんなに小さくても注意が必要よ。","ENG":"Any wound from a Category 4 C.O. cannot be underestimated, no matter how light it is.","TWN":"不要小看4類侵蝕體造成的傷口，無論傷口有多小。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"으음? 표정이 왜 그래? 괜찮아, 앨리스?","JPN":"ん？　どうしたの？　大丈夫、アリス？","ENG":"Hmm? What's wrong? Are you okay, Alice?","TWN":"嗯？你那是什麼表情？你還好嗎，艾莉絲？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"아직 어디 아픈 데라도 있어?","JPN":"まだどこか痛むところがあるの？","ENG":"Does it still hurt somewhere?","TWN":"還有什麼地方痛嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……이젠 길고양이라고 안 부르네?","JPN":"……もう、野良猫って呼ばないんだな。","ENG":"...You're not calling me stray cat anymore.","TWN":"……你不叫我流浪貓了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"……음?","JPN":"……ん？","ENG":"...Hmm?","TWN":"……嗯？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 뭐야~? 안 그런 척하더니, 계속 신경 쓰고 있었던 거야~?","JPN":"ふふ、なぁに～？　意外ね。そんなこと気にしてたの？","ENG":"Fu fuu, is that it? I didn't think you cared, but did you?","TWN":"呵呵，什麼啊～？原來你在意啊～"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그, 그런 거 아니거든!?","JPN":"そ、そうじゃない！","ENG":"N-no, I wasn't!","TWN":"才、才不是那樣？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"돌아올 곳이 있고, 널 기다리는 사람들이 있는데……. 네가 왜 길고양이겠어.","JPN":"帰る場所があって、あなたを待ってる人たちがいるのに……あなたが野良猫なわけないでしょ。","ENG":"You have a home, and people waiting for you to come back... You're not a stray cat.","TWN":"你有家可回，還有人在等你……你怎麼會是流浪貓呢？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"넌 결국 훌륭하게 스스로 그림자를 끊어냈잖아?","JPN":"あなたは結局、自分で見事シャドウを断ち切ったじゃない。","ENG":"Plus, you defeated your own Shadow with excellence, no?","TWN":"最後，你自己成功斬斷了暗影吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그러니 이제부터 넌 야크샤의 일원이자, 우리의 가족이야.","JPN":"だから、これからあなたはヤクシャーの一員で、私たちの家族よ。","ENG":"Now, you're a member of the Yaksha Division, and also our family.","TWN":"所以從現在開始，你不僅是夜叉的一員，也是我們這個大家庭的一員了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"네가 도와준 거잖아? 그걸로 괜찮아?","JPN":"でも、お前に手伝ってもらったじゃないか。それでもいいのか？","ENG":"But you helped me. Is that okay?","TWN":"但那是你幫了我啊？這也沒關係嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"물론이지, 각오를 보여준 것만으로도 충분해.","JPN":"もちろん、覚悟を見せてくれただけで十分よ。","ENG":"Of course. Just showing your determination is enough.","TWN":"當然，只要表現出決心就足夠了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"쥐스틴도 펑펑 울었지만 결국 해냈거든.","JPN":"ジュスティーヌもわんわん泣いてたけど結局やってのけたしね。","ENG":"Justine cried the whole way, but she also did it.","TWN":"潔絲婷當時也哇哇哭得很慘，但最後也做到了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"참나, 그 완두콩이랑 비교하니까 갑자기 맥 빠지네.","JPN":"ったく、あのちんちくりんと比べられると拍子抜けするな。","ENG":"Ugh, comparing me to green pea kinda ruined it.","TWN":"呃，你要是拿我和那顆豌豆比的話，我可就要生氣了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 그래도 고생했어, 앨리스.","JPN":"ふふ、でも本当にお疲れ様、アリス。","ENG":"Fu fuu, but still. Great work, Alice.","TWN":"呵呵，總之，辛苦你了，艾莉絲。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"흐음~ 하지만 애칭이 없어진 건, 살짝 서운할지도~?","JPN":"うーん、でもやっぱりあだ名がなくなっちゃったのはちょっと寂しいかな。","ENG":"Hmm... But not calling you by a nickname is kind of sad, don't you think?","TWN":"嗯……不過不能叫你的外號，總覺得有些失落呢～？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"역시 검은 고양이니까, 네로 어떨까?","JPN":"そうねえ、黒い猫だから「ネロ」とかはどう？","ENG":"Since you're a black cat, how does Nero sound?","TWN":"畢竟是隻黑貓，不如叫諭吉吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"구려.","JPN":"ダサい。","ENG":"Terrible.","TWN":"討厭。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후. 딱 잘라서 거절하다니, 너무하네.","JPN":"ふふ、そんなに即答で断らなくてもいいじゃない。","ENG":"Fu fuu. Ouch. You didn't have to reject it so harshly.","TWN":"哎呀？拒絕得這麼乾脆，真是過分。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"고마워, 부전대장.","JPN":"ありがとう、副戦隊長。","ENG":"Thanks, Deputy Commander.","TWN":"謝謝你，副戰隊長。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"음? 갑자기 뭐가?","JPN":"え？　何、急に？","ENG":"Mm? About what?","TWN":"嗯？突然謝我做什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"벌써 몇 번이나 날 구해줬잖아.","JPN":"もう何回もアタシを助けてくれたじゃないか。","ENG":"You saved my life so many times already.","TWN":"你已經救了我好幾次了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그동안 한 번도 고맙다고 말하지 않았던 것 같아서.","JPN":"今まで一度もちゃんとお礼を言ってなかったなと思って。","ENG":"But I think I never thanked you once.","TWN":"我以前好像從來沒有說過謝謝。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"흐응, 그런 말을 들으니 부끄러운데?","JPN":"ふうん、そんなこと言われると照れるね。","ENG":"Hmm, I feel a little embarrassed hearing those words from you.","TWN":"嗯，聽到這樣的話，我都有點不好意思了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……사실 말이야.","JPN":"……実はな。","ENG":"...But you know.","TWN":"其實……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"사실, 무서웠어……. 내 얼굴과 똑같은 도플갱어와 마주했을 때…….","JPN":"実は、怖かった……自分の顔そっくりのドッペルゲンガーを目にした時……","ENG":"I was scared... when I faced the Doppelganger who looked just like me...","TWN":"其實我很害怕……當我遇到和我長得一模一樣的二重身的時候……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"마치 화재 현장에 처음 출동 나갔던 그때처럼.","JPN":"火災現場に初めて出動した時みたいだった。","ENG":"It was like that time when I was on my first fire mission.","TWN":"我第一次去火災現場時也是。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"냉동 창고 화재였거든. 민간인이 서른 명이나 죽고, 뛰어 들어간 동료들마저도 죽었어.","JPN":"冷凍倉庫での火災だったよ。民間人が30人も死んで、炎の中に飛び込んだ仲間たちも死んだ。","ENG":"There was a fire in a refrigerated warehouse. Thirty civilians, including my colleagues who went in to save them, died.","TWN":"那是一場發生在冷凍倉庫的火災。三十個平民……就連和我一同進去的同事也遇難了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그때…… 나는 의욕만 앞섰지, 아무것도 하지 못했고.","JPN":"あの時……アタシはやる気だけはあったけど、結局何も出来なかったし。","ENG":"I was... ahead of myself and couldn't do anything.","TWN":"當時……我空有滿腔熱血，卻什麼也做不了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"항상 꿈에 그리던 소방관이었는데, 그런 내 자신이 너무나 무력해서 견딜 수가 없었어.","JPN":"ずっと夢見てきた消防士になれたのに、何もできなかった自分が無力すぎて……耐えられなかった。","ENG":"I always dreamt of becoming a firefighter. But seeing how weak I was, I couldn't bear it.","TWN":"我的夢想一直是成為一名消防員，我無法忍受這樣的自己，無助，而且渺小。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"포기하고 싶었어……. 도망치고 싶었어…….","JPN":"諦めたかった……逃げ出したかった……","ENG":"I wanted to give up... I wanted to run away...","TWN":"我想過放棄……想過逃跑……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그런 나에게 힘이 되어준 사람이 대장님이었어.","JPN":"そんなアタシに、隊長が力になってくれたんだ。","ENG":"But thanks to Captain, I was able to rise again.","TWN":"是隊長給我了力量。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"구조자의 목숨과 스스로의 목숨. 훌륭한 소방관이라면 어느 쪽도 포기해선 안 된다고.","JPN":"救助者の命と自分の命。立派な消防士ならどっちも諦めちゃダメだって。","ENG":"He said that an excellent firefighter knows how to save both the rescuee's and the rescuer's lives.","TWN":"求救者和自己的生命。一名優秀的消防員，絕不能放棄任何一方。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그렇기에 양쪽 모두를 구할 수 있도록…….","JPN":"だから、どっちも救えるように……","ENG":"He said that in order to be able to save both...","TWN":"所以，為了拯救所有人……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"웨이트 트레이닝으로 근력을 키우고, 효율적으로 행동할 수 있게 소방 지식을 익히라고.","JPN":"筋トレで筋力をつけて、効率的に動けるように消防知識を頭に入れろって。","ENG":"I had to build my strength through weight training and learn firefighting knowledge to act more efficiently.","TWN":"要透過負重訓練增強力量，學習消防知識，才能更高效地行動。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그렇게 가르쳐 주셨거든.","JPN":"そう教えてくれたんだ。","ENG":"That's what he taught me.","TWN":"這都是他教我的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"……좋으신 분이셨네.","JPN":"……立派な方だったのね。","ENG":"...He sounds like a great person.","TWN":"……他是一個好人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"맞아. 우리 구조팀에 없어서는 안 되는 분이셨지.","JPN":"ああ、うちの救助チームにとって、必要な存在だった。","ENG":"He was. He was indispensable to our rescue team.","TWN":"沒錯。他是我們救援隊不可缺少的支柱。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"라이오넬 전대장이라는 분도 야크샤에 없어서는 안 되는 분이었겠지?","JPN":"ライオネル戦隊長って人も、ヤクシャーにとってなくてはならない存在だったんだろう？","ENG":"Commander Lionel was someone like that to Yaksha too, right?","TWN":"萊諾戰隊長也一定是夜叉中不可或缺的存在吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"여기있는 모두가 한마음으로 그 사람을 신뢰하고 있었으니까.","JPN":"ここのみんながあの人を心から信頼してたからな。","ENG":"Because everyone here seems to trust him.","TWN":"這裡的每個人都全心全意地信任他。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"응. 나한테는 생명의 은인이자, 모든 환상종 동포들의 아버지 같은 분이었어.","JPN":"うん、私にとっては命の恩人で、すべての幻想種の同胞にとって父親のような方だったよ。","ENG":"Correct. I owe my life to him, and he's like a father figure to all Bygone compatriots.","TWN":"沒錯，他是我的救命恩人，對所有夢幻品種同伴而言也是如父親一般存在的人物。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"아버지라고?","JPN":"父親？","ENG":"A father figure?","TWN":"父親？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>세계가 환상종의 존재를 수용할 때까지, 동포들의 삶을 보장한다.</color>","JPN":"<color=#ffd34c>世界が幻想種の存在を受け入れるようになるまで、同胞たちの生活を保障する。</color>","ENG":"<color=#ffd34c>Until the world is able to accept the existence of Bygones, I guarantee the safety of my compatriots.</color>","TWN":"<color=#ffd34c>保障我們同伴的生命安全，直到世界能夠接受夢幻品種的存在。</color>"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"전대장님께서는 동포들이 숨어살지 않아도 되는 세계를 바라셨어.","JPN":"戦隊長は、同胞たちが堂々と生きられるような世界を望んでいた。","ENG":"Commander wanted a world where his compatriots didn't have to live in hiding.","TWN":"戰隊長想要一個能讓他的同伴不必再次躲藏的世界。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그걸 위해서 전대장님은 관리국과 계약을 맺고, 야크샤 전대를 설립하셨지.","JPN":"そのために戦隊長は管理局と契約を交わし、ヤクシャー戦隊を立ち上げたの。","ENG":"To achieve that, he made a contract with the Administration and established the Yaksha Division.","TWN":"為此，戰隊長與管理局簽訂了合約，創立了夜叉戰隊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"나는……. 야크샤의 부전대장으로서 반드시 그 분의 유지를 이어가야 해.","JPN":"私は……ヤクシャーの副戦隊長として、あの方の意志を受け継がないといけない。","ENG":"As Deputy Commander... I must continue his legacy.","TWN":"我……作為夜叉的副戰隊長，我必須繼承他的遺志。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"오직 그것만이 내 유일한 바람이니까.","JPN":"ただそれだけが、私の唯一の願いだからね。","ENG":"Because that's my only wish.","TWN":"因為這是我唯一的願望。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그랬구나.","JPN":"そうだったのか。","ENG":"I see…","TWN":"原來如此。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이 전대에 있으면서도 나는 한 번도 너희 사정을 이해하려고 하지 않았어.","JPN":"この戦隊に身を置きながら、アタシは一度もおまえらの事情を理解しようと思わなかった。","ENG":"I don't think I've tried to understand what you're all going through after joining this division.","TWN":"即使我身在戰隊，我也從未嘗試去理解你們的處境。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"관리국도, 야크샤 전대도 그저 수단으로만 생각하고 있었으니까.","JPN":"管理局もヤクシャー戦隊も、手段としか考えてなかった。","ENG":"I just thought that the Administration and the Yaksha Division were all a means to an end.","TWN":"因為管理局也好，夜叉戰隊也好，我之前都把你們當做實現我自己目標的手段。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"세계를 지킨다느니, 인과를 관리한다느니. 그런 복잡한 이야기는 여전히 잘 모르겠어.","JPN":"世界を守るだの、因果を管理するだの……そういう複雑な話は正直まだよくわからない。","ENG":"Protecting the world and managing causality... It's all just too complicated for me.","TWN":"守護世界，管理因果。這些太複雜，我還是看不透。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"하지만 적어도…….","JPN":"でも、せめて……","ENG":"But still...","TWN":"但至少……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"적어도 이젠 관리국이 항상 최선의 결과를 위해 행동한다는 건 알겠어.","JPN":"管理局が常に最善の結果のために動いているってことはわかった。","ENG":"What I do get is that the Administration acts for the best outcome.","TWN":"至少現在我知道，管理局的行事總是為了最好的結果。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그 최선을 위해서, 너희가 얼마나 노력하고…… 또 희생하고 있는지도 말이야.","JPN":"そのためにおまえらがどれだけ頑張って……様々なものを犠牲にしているのかもな。","ENG":"And the efforts you put into it... and the sacrifices you made.","TWN":"為了最好的結果，你們到底要付出多少努力……會不會又要做出犧牲。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그러니 나도 돕겠어. 야크샤의 일원으로서, 환상종의 동포로서 그리고…….","JPN":"だから、アタシも手伝う。ヤクシャーの一員として、幻想種の同胞として。そして……","ENG":"So, I want to help. As a member of the Yaksha Division, as a Bygone compatriot, and...","TWN":"所以，我也想要幫忙。作為夜叉的一員，作為夢幻品種的同伴，還有……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"가, 가족으로서.","JPN":"か、家族として。","ENG":"A-as family.","TWN":"作為家、家人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"제, 젠장! 이거 부끄럽잖아! 가족은 취소야, 취소!","JPN":"く、くそ！　恥ずかしいなこれ！　家族はなしだ、なし！","ENG":"G-geez! This is so embarrassing! Cancel the last part about family!","TWN":"該、該死！這太難為情了！家人這個詞我收回，收回！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"……푸흡!","JPN":"……ぷふっ！","ENG":"...Pfft!","TWN":"……噗哧！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"아하하하하! 정말이지! 솔직하지 못한 점이 귀엽다니까!","JPN":"あはははは！　本当もう、素直じゃないとこが可愛いんだよね！","ENG":"Ah hah hah hah hah! Oh, you! I think it's cute when you're being sincere!","TWN":"哈哈哈哈！真是的！你口是心非這點，真的很可愛！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"우, 웃지말라고! 제기랄!","JPN":"わ、笑うなよ！　ちくしょう！","ENG":"S-stop laughing! Dammit!","TWN":"別、別笑啊！可惡！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"자, 그럼 가족이 된 기념 선물이야.","JPN":"ほら、家族になった記念のプレゼント。","ENG":"Here. It's a gift to commemorate you becoming a part of our family.","TWN":"好了，這是禮物，紀念你成為我們的家人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"음? 이건?","JPN":"え、これは……？","ENG":"Mm? It's a...","TWN":"嗯？這是？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"꼬리 리본. 이제 길고양이가 아니니까 말이지.","JPN":"尻尾のリボン。もう野良猫じゃないからね。","ENG":"It's a tail ribbon. Since you're no longer a stray cat.","TWN":"尾巴絲帶。你以後不再是流浪貓了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"길을 잃어버려도 금방 찾아낼 수 있도록. <color=#ffd34c>우리 고양이</color>라는 뜻이야.","JPN":"道に迷ってもすぐに見つけられるように。<color=#ffd34c>うちの猫</color>って意味よ。","ENG":"It's so that we can easily find you even if you lose your way. It means that you're now <color=#ffd34c>our cat</color>.","TWN":"這樣即使<color=#ffd34c>我們的貓咪</color>迷路了，我們也能很快找到你。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"왠지 묘하게 반려동물 다루는 것 같은 느낌인데, 이거……?","JPN":"なんか、ペット扱いされてる気がするんだけど……？","ENG":"This kinda feels like you're treating me like a pet...","TWN":"有種被當成寵物對待的微妙感……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"어라? 들켜버렸네?","JPN":"え、バレちゃった？","ENG":"Oh? Did you figure it out already?","TWN":"嗯？被你發現了啊？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"진짜 그런 뜻이었다고?","JPN":"マジだったのかよ！","ENG":"That wasn't a joke?","TWN":"你真是這個意思？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이게 진짜……!!","JPN":"この……！！","ENG":"C'mon...!","TWN":"可惡……！！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"아하, 아하하하! 미안, 미안! 농담이야! 농담! 아하하하!!","JPN":"あはははは！　ごめんごめん！　冗談よ、冗談！　あははは！！","ENG":"Ah hah, ah hah hah hah! Sorry! I'm just messing with you! It's a joke! Ah hah hah hah!!","TWN":"哈哈，哈哈哈哈！抱歉，抱歉！我在開玩笑！開玩笑！哈哈哈哈！！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"각오하라고!","JPN":"覚悟しとけよ！","ENG":"You asked for it!","TWN":"做好覺悟吧！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"부전대장이라고 봐주지는 않을 테니까!","JPN":"副戦隊長だからって容赦しないからな！","ENG":"I'm not gonna go easy on you just because you’re the Deputy Commander!","TWN":"我不會因為你是副戰隊長就對你手下留情的！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"아하하! 내가 잘못했다니까……!","JPN":"あはは！　だからごめんて……！","ENG":"Ah hah hah! I said I was sorry...!","TWN":"哈哈哈！我都說我錯了……！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"간지러워, 그만……!! 그만!! 아하하하……!!","JPN":"くすぐったいよ、やめ……！！　やめて！！　あははは……！！","ENG":"That tickles! Stop...! Stop!! Ah hah hah hah...!!","TWN":"好癢，停下……！！停下！！啊哈哈哈……！！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이렇게 늦은 시간까지 고생이네~","JPN":"こんな夜遅くまで頑張ってるね～","ENG":"I see you're working late.","TWN":"工作到現在，真是辛苦你了~"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"오셨습니까요, 부전대장님.","JPN":"副戦隊長でやんすか。","ENG":"Hello, Deputy Commander.","TWN":"你來了，副戰隊長。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그래서? 부탁한 건 어떻게 됐을까?","JPN":"で、進捗はどう？","ENG":"So? How's the thing I asked going?","TWN":"所以？我拜託你的事情如何了？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"키히히! 걱정하지 않으셔도 됩니다요. 아주 순조롭습니다요!","JPN":"キヒヒ！　ご心配なく。きわめて順調でやんす！","ENG":"Kehehe! No need to worry. It's going smoothly.","TWN":"嘻嘻！不用擔心，進行得非常順利！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"도플갱어 그림자를 격파하고 획득한 이 이터니움…….","JPN":"ドッペルゲンガーのシャドウを撃破して手に入れたこのエタニウム……","ENG":"The Eternium we obtained after defeating the Doppelganger Shadow...","TWN":"從被擊敗的二重身暗影身上得到的這塊永恆之金……"},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"원래 그림자로부터 획득한 이터니움은 오염도가 심각해서 폐기하는 게 원칙이지만.","JPN":"本来であれば、シャドウから獲得したエタニウムは汚染度が高いので破棄するべきでやんすが……","ENG":"Normally, we'd dispose of it because Eternium from Shadows is too contaminated, but...","TWN":"原本已經被嚴重污染，原則上是當做廢棄物處理的。"},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"반대로 그림자였을 때의 고유한 침식파장을 그대로 간직하고 있다는 뜻이기도 합니다요.","JPN":"言いかえると、シャドウ固有の侵食波長を溜め込んでいるという意味になるでやんす。","ENG":"On the flip side, it also means that it contains the unique Corruption ray of when it was a Shadow.","TWN":"但反過來說，這也表示它保留了暗影時特有的侵蝕波長。"},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"다시 말해, 침식파장을 분석하여 엘리시움 그림자만의 고유한 파형을 알아낼 수만 있다면.","JPN":"つまり、侵食波長を分析してエリシウムシャドウ固有の波形を解析できれば……","ENG":"In other words, if we can analyze the Corruption ray and isolate the unique wavelength of Elysium Shadows...","TWN":"也就是說，如果我們能夠分析侵蝕波長，找出愛樂組織暗影特有的波形的話。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"좌표 입력 없이 침식파를 추적하는 장치를 개발할 수 있을 겁니다요.","JPN":"座標を入力せずとも、侵食波を追跡する装置を作れるはずでやんす！","ENG":"we'll be able to develop a device that can track it without having to enter the coordinates.","TWN":"就能夠開發出一種無需輸入座標即可跟蹤侵蝕波的設備。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그럼, 가변 심도에 숨어있는 엘리시움의 근거지를 수색하는 것도 충분히 가능합니다요!","JPN":"そうすれば、可変深度に隠れているエリシウムの本拠地を捜索することだって十分可能になるでやんす！","ENG":"Then, we'll be able to search the base of Elysium that's hidden in the variable depths!","TWN":"那麼，我們就有很大的機率可以偵察到樂團隱藏在可變深度的根據地！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"마침내……. 마침내 가변 심도 좌표에 진입할 수 있게 되는 건가?","JPN":"ついに……ついに可変深度の座標に進入できるのかな。","ENG":"Does... Does that mean that we'll finally be able to enter the variable depth coordinates?","TWN":"終於……我們終於能夠進入可變深度座標了嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>필하모닉 홀</color>…….","JPN":"<color=#ffd34c>フィルハーモニーホール</color>……","ENG":"<color=#ffd34c>Philharmonic Hall</color>...","TWN":"<color=#ffd34c>管弦樂廳</color>……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"어쩌면 그곳에서 전대장님에 대한 단서를 찾을 수 있을지도 몰라.","JPN":"もしかしたら、そこで戦隊長の手がかりが見つかるかもしれない。","ENG":"We might be able to find clues about Commander there.","TWN":"或許，我們能在那裡找到關於戰隊長的線索。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"걱정 붙들어 매시는 겁니다요!","JPN":"心配は要らないでやんす！","ENG":"Hold on to your worries!","TWN":"請放心吧！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"필요한 건 오로지 시간과 예산뿐입니다요! 반드시 성공시키겠습니다요!","JPN":"必要なのはただ二つ、時間と予算のみでやんす！　必ず成功させてみせるでやんす！","ENG":"All we need right now is time and budget! I'll make sure it works!","TWN":"只需要些時間和預算！我一定會成功的！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"물론이야, 쥐스틴.","JPN":"もちろんよ、ジュスティーヌ。","ENG":"Of course, Justine.","TWN":"當然，潔絲婷。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이번 건은 엘리시움의 토벌과 전대장님의 행방에 대한 단서를 얻을 수 있는 좋은 기회야.","JPN":"今回の件は、エリシウムの討伐と戦隊長の行方に関する手がかりを得られるかもしれない貴重なチャンスなの。","ENG":"This is a good opportunity to eliminate Elysium and obtain clues to Commander's whereabouts.","TWN":"這是個討伐樂團，以及獲取戰隊長線索的好機會。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"지원은 아낌없이 해주겠어. 대신 결과를 보여줘, 쥐스틴.","JPN":"支援は惜しまない。その代わり、結果で示して、ジュスティーヌ。","ENG":"You have my full support. In return, I expect results, Justine.","TWN":"我會毫不吝嗇地給予你支持。但我要看到結果，潔絲婷。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"분석은 순조롭게 진행 중이지만…… 한 가지 걸리는 점이 있습니다요.","JPN":"分析は順調でやんすが……一つ、ひっかかることがあるでやんす。","ENG":"The analysis is going well, but... there's one concern.","TWN":"分析工作進展順利……但有一個問題。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"도플갱어 타입 그림자의 정체는 클리파 에너지에 의해 발생하는 복제체.","JPN":"ドッペルシャドウの正体は、クリファエネルギーによって発生する複製個体。","ENG":"Doppelganger-type Shadows are clones made from the Qlipha energy.","TWN":"二重身型暗影的真實身份是逆卡巴拉能量所創造的複製體。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"하지만 신참의 도플갱어는 도플갱어 타입이면서 동시에 데몬 타입이기도 했습니다요.","JPN":"でも新入りのドッペルゲンガーは、ドッペルゲンガータイプでありながらデーモンタイプでもあったでやんす。","ENG":"But the rookie's Doppelganger was both a Doppelganger-type and Demon-type.","TWN":"但新人的二重身，既是二重身型又是惡魔型。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"뭔가 이상한 일이라고 생각하지 않습니까요?","JPN":"なんかおかしいと思わないでやんすか？","ENG":"Don't you think that's a little strange?","TWN":"出現這種情況不是有些奇怪嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"짐작가는 게 하나 있어.","JPN":"心当たりはある。","ENG":"I have a guess as to why that happened.","TWN":"我有一個猜測。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"도플갱어 타입은 어쨌든 반드시 원본이 필요해.","JPN":"ドッペルゲンガータイプの発生には必ずオリジナルが必要になる。","ENG":"Doppelganger-types always need the original.","TWN":"無論如何，二重身型肯定需要參照本體。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"녀석들은 오리지널리티가 없는 허깨비에 불과하니까.","JPN":"やつらはオリジナリティのない虚像にすぎないからね。","ENG":"Because they're just an illusion with no originality.","TWN":"這些傢伙只不過是原型的鬼影。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그리고 그런 허깨비의 복제체로 발생한 것이 데몬 타입, 엘리시움의 그림자였다는 뜻은…….","JPN":"で、その虚像の複製として発生したのがデーモンタイプ、エリシウムのシャドウだったということは……","ENG":"So, for a clone of an illusion to be a Demon-type and an Elysium Shadow means...","TWN":"而會以樂團的暗影的複製體出現……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"잠깐, 설마……!?","JPN":"えっ、まさか……！？","ENG":"Wait, it can't be...!","TWN":"等等，不會吧……？！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그럼 엘리시움의 그림자가…… 신참 녀석이 그림자가 된 후의 모습이라는 겁니까요?","JPN":"あのエリシウムのシャドウは……新入りがシャドウになった後の姿ってことでやんすか？","ENG":"Then the Elysium Shadow is... what the rookie will become after becoming a Shadow?","TWN":"那個愛樂組織的暗影……就是新人變成侵蝕體後的樣子？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그건 말도 안 됩니다요!","JPN":"あり得ないでやんす！","ENG":"That's impossible!","TWN":"這也太荒謬了！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"아무리 허접해도…… 그 녀석, 하이브 컨트롤이 선택한 미래의 전대장입니다요!","JPN":"いくらヘタクソとはいえ……あいつはハイブコントロールに選ばれた未来の戦隊長でやんす！","ENG":"Even if she's a noob... She's our future Commander chosen by Hive Control itself!","TWN":"就算那個傻瓜現在很弱……那也是巢穴控制系統選定的未來戰隊長！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그런데 어째서 그런 비참한 최후를……!","JPN":"それなのに、なんであんな悲惨な最期を……！","ENG":"How can she have such a miserable end...?!","TWN":"怎麼會有這樣悲慘的結局啊……！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"……확실한 건 아니야.","JPN":"……まだ断言はできない。","ENG":"...It's just as assumption.","TWN":"……這點還不確定。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"어쩌면 그저 수많은 인과의 분기점에서 발생한 일종의 돌연변이일 수도 있겠지.","JPN":"もしかしたら、数多の因果の分岐点で発生した突然変異なだけかも。","ENG":"Maybe it's just a mutant that occurred in one of the countless causality points.","TWN":"也許這只是在多個因果點上發生的一種突變。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하지만 관측한 이상, 절대 간과할 수는 없어.","JPN":"でも観測した以上、その可能性は無視できない。","ENG":"But since we have seen it ourselves, we can't just shrug it off.","TWN":"但既然觀察到了，就不能忽視。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"각자 출신이 다르다고 해도, 야크샤의 일원은 서로 가족이나 다름없으니까.","JPN":"出身は違えど、ヤクシャーのみんなは家族同然だからね。","ENG":"Even if we're all from different backgrounds, the Yaksha members are still like family to each other.","TWN":"儘管大家有著不同的出身，但夜叉的隊員就像家人一樣。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그 아이가 그림자에 삼켜지지 않도록, 반드시 내가 지켜내겠어.","JPN":"あの子がシャドウに飲み込まれないように、必ず守ってみせる。","ENG":"So, for her not to be swallowed by a Shadow, I'll protect her at all costs.","TWN":"我一定會保護那個孩子，不讓她被暗影吞噬。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"분명히 그때 그 느낌은…….","JPN":"確かにあの時のあの感覚は……","ENG":"What I felt that day...","TWN":"這個感覺，分明和那時……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"저쪽에서 뭔가 폭발하는 소리가 났어!","JPN":"あっちから何かが爆発する音が聞こえた！","ENG":"I just heard an explosion over there!","TWN":"那邊有東西爆炸的聲音！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"폭발하는 소리라고? 설마……!?","JPN":"爆発音？　まさか……！？","ENG":"An explosion? Could that be..?!","TWN":"爆炸的聲音？難道是……？！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"부, 부전대장님! 큰일났습니다요!","JPN":"ふ、副戦隊長！　大変でやんす！","ENG":"D-Deputy Commander! We're in big trouble!","TWN":"副、副戰隊長！我們有大麻煩了！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L34_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"인근 구역에서 각성 붕괴와 유사한 침식파의 에너지 폭풍이 발생했습니다요!","JPN":"近隣区域で、覚醒崩壊に類似した侵食波のエネルギー爆風が発生したでやんす！","ENG":"A Corruption ray energy storm similar to an Awakening Collapse just occurred in a nearby area!","TWN":"附近區域發現了與覺醒崩潰類似的侵蝕波能量風暴！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그림자입니다요! 그림자가 나타났습니다요!","JPN":"シャドウでやんす！　シャドウが現れたでやんす！","ENG":"It's a Shadow! A Shadow has appeared!","TWN":"是暗影！暗影出現了！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"각성 붕괴 현상과 유사하다면…… <color=#ffd34c>도플갱어 신드롬</color>인가?","JPN":"覚醒崩壊現象に似てるってことは……<color=#ffd34c>ドッペルゲンガーシンドローム</color>？","ENG":"If it's similar to an Awakening Collapse... is it <color=#ffd34c>Doppelganger Syndrome</color>?","TWN":"如果與覺醒崩潰現象類似的話……會是<color=#ffd34c>二重身</color>類型嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그때 느꼈던 폭발과 폭음…….","JPN":"あの時感じた爆発と爆音……","ENG":"The blast and its sound I felt...","TWN":"那時候感覺到的爆炸和聲音……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그리고 어지러움증과 멀미하는 것 같은 구토감…….","JPN":"そしてあの眩暈と吐き気……","ENG":"and the dizziness and nausea that made me want to throw up...","TWN":"還有類似暈車一樣的反胃和頭痛感……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……틀림없어.","JPN":"……間違いない。","ENG":"...It has to be it.","TWN":"……不會錯的。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L46_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그 날 화재에서 워치를 만졌을 때와 똑같은 기분이었어.","JPN":"あの日火災現場でウォッチに触れた瞬間と同じ感覚だった。","ENG":"It was the same feeling I had when I touched the Watch on the day of the fire.","TWN":"這種感覺，和火災那天碰到能量環時的一樣。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"설마, 그 화재에서 일어났던 폭발이……?","JPN":"まさか、あの火災で起きた爆発が……？","ENG":"Could it be that the explosion from the fire was...","TWN":"難道那次的爆炸也……？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};